eventHandlers.handlerCode:
var rawData = ctx.controls.mongoDb.find('baseproducts', {});
var data = [];
for (var i = 0; i < rawData.length; i++) {
  var r = rawData[i];
  data.push({
    sku: r.sku || '',
    title: r.title || '',
    category: r.category || '',
    msrp: r.msrp ? r.msrp.toLocaleString() + '원' : '-',
    basePrice: (r.pricing && r.pricing.basePrice) ? r.pricing.basePrice.toLocaleString() + '원' : '-',
    quantity: (r.inventory && r.inventory.isInfinite) ? '무제한' : ((r.inventory && r.inventory.quantity != null) ? r.inventory.quantity.toLocaleString() : '-'),
    leadTime: (r.leadTime != null) ? r.leadTime : '-',
    status: r.status === 'active' ? '판매중' : r.status,
    createdAt: r.createdAt ? r.createdAt.substring(0, 10) : ''
  });
}
ctx.controls.dgvProducts.dataSource = data;
ctx.controls.lblCount.text = '총 ' + data.length + '건';
ctx.controls.lblStatus.text = '데이터 로드 완료 (' + data.length + '건)';
ctx.controls.lblStatus.foreColor = '#2E7D32';

var keyword = ctx.controls.txtSearch.text;
var catIdx = ctx.controls.cmbCategory.selectedIndex;
var categories = ['전체', 'gifts', 'household'];
var filter = {};
var conditions = [];
if (keyword) {
  conditions.push({ '$or': [{ 'title': { '$regex': keyword, '$options': 'i' } }, { 'sku': { '$regex': keyword, '$options': 'i' } }] });
}
if (catIdx > 0) {
  conditions.push({ 'category': categories[catIdx] });
}
if (conditions.length === 1) {
  filter = conditions[0];
} else if (conditions.length > 1) {
  filter = { '$and': conditions };
}
var rawData = ctx.controls.mongoDb.find('baseproducts', filter);
var data = [];
for (var i = 0; i < rawData.length; i++) {
  var r = rawData[i];
  data.push({
    sku: r.sku || '',
    title: r.title || '',
    category: r.category || '',
    msrp: r.msrp ? r.msrp.toLocaleString() + '원' : '-',
    basePrice: (r.pricing && r.pricing.basePrice) ? r.pricing.basePrice.toLocaleString() + '원' : '-',
    quantity: (r.inventory && r.inventory.isInfinite) ? '무제한' : ((r.inventory && r.inventory.quantity != null) ? r.inventory.quantity.toLocaleString() : '-'),
    leadTime: (r.leadTime != null) ? r.leadTime : '-',
    status: r.status === 'active' ? '판매중' : r.status,
    createdAt: r.createdAt ? r.createdAt.substring(0, 10) : ''
  });
}
ctx.controls.dgvProducts.dataSource = data;
ctx.controls.lblCount.text = '총 ' + data.length + '건';
var msg = '';
if (keyword && catIdx > 0) {
  msg = '"' + keyword + '" + ' + categories[catIdx] + ' 검색: ' + data.length + '건';
} else if (keyword) {
  msg = '"' + keyword + '" 검색: ' + data.length + '건';
} else if (catIdx > 0) {
  msg = categories[catIdx] + ' 필터: ' + data.length + '건';
} else {
  msg = '전체 조회: ' + data.length + '건';
}
ctx.controls.lblStatus.text = msg;
ctx.controls.lblStatus.foreColor = '#1565C0';

ctx.controls.txtSearch.text = '';
ctx.controls.cmbCategory.selectedIndex = 0;
var rawData = ctx.controls.mongoDb.find('baseproducts', {});
var data = [];
for (var i = 0; i < rawData.length; i++) {
  var r = rawData[i];
  data.push({
    sku: r.sku || '',
    title: r.title || '',
    category: r.category || '',
    msrp: r.msrp ? r.msrp.toLocaleString() + '원' : '-',
    basePrice: (r.pricing && r.pricing.basePrice) ? r.pricing.basePrice.toLocaleString() + '원' : '-',
    quantity: (r.inventory && r.inventory.isInfinite) ? '무제한' : ((r.inventory && r.inventory.quantity != null) ? r.inventory.quantity.toLocaleString() : '-'),
    leadTime: (r.leadTime != null) ? r.leadTime : '-',
    status: r.status === 'active' ? '판매중' : r.status,
    createdAt: r.createdAt ? r.createdAt.substring(0, 10) : ''
  });
}
ctx.controls.dgvProducts.dataSource = data;
ctx.controls.lblCount.text = '총 ' + data.length + '건';
ctx.controls.lblStatus.text = '새로고침 완료 (' + data.length + '건)';
ctx.controls.lblStatus.foreColor = '#2E7D32';

var grid = ctx.controls.dgvProducts;
if (grid.dataSource && grid.dataSource.length > 0 && ctx.eventArgs.rowIndex >= 0) {
  var row = grid.dataSource[ctx.eventArgs.rowIndex];
  ctx.controls.lblStatus.text = '선택: [' + row.sku + '] ' + row.title + ' | ' + row.msrp + ' | 재고: ' + row.quantity;
  ctx.controls.lblStatus.foreColor = '#424242';
}
